import React, { useEffect, useMemo, useRef, useState } from 'react';
import { View, Text, Button, StyleSheet, FlatList, TouchableOpacity, AppState } from 'react-native';

const TOKEN_PREFIX = 'local_';
const TOKEN_LENGTH = 24;

function generateRandomToken(length = TOKEN_LENGTH) {
  const chars = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  let token = TOKEN_PREFIX;
  for (let i = 0; i < length; i++) {
    token += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return token;
}

function createSessionToken() {
  return {
    id: generateRandomToken(),
    createdAt: Date.now(),
    expiresAt: Date.now() + 1000 * 60 * 60 * 24,
    synced: false,
  };
}

export function useOfflineSessionTokens() {
  const [tokens, setTokens] = useState([]);
  const [isOffline, setIsOffline] = useState(false);
  const appStateRef = useRef(AppState.currentState);

  const addToken = () => {
    const token = createSessionToken();
    setTokens(prev => [token, ...prev]);
    return token;
  };

  const removeToken = (id) => {
    setTokens(prev => prev.filter(item => item.id !== id));
  };

  const markTokenSynced = (id) => {
    setTokens(prev =>
      prev.map(item => (item.id === id ? { ...item, synced: true } : item))
    );
  };

  const clearExpiredTokens = () => {
    const now = Date.now();
    setTokens(prev => prev.filter(item => item.expiresAt > now));
  };

  useEffect(() => {
    const interval = setInterval(clearExpiredTokens, 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const subscription = AppState.addEventListener('change', nextAppState => {
      appStateRef.current = nextAppState;
    });
    return () => subscription?.remove?.();
  }, []);

  return {
    tokens,
    isOffline,
    setIsOffline,
    addToken,
    removeToken,
    markTokenSynced,
    clearExpiredTokens,
  };
}

